def _dremio_space_to_nested(dremio_space: DremioSpace) -> DremioSpaceNested:
    """Convert flat DremioSpace to nested format."""
    attrs = DremioSpaceAttributes()
    _populate_dremio_space_attrs(attrs, dremio_space)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dremio_space, _DREMIO_SPACE_REL_FIELDS, DremioSpaceRelationshipAttributes
    )
    return DremioSpaceNested(
        guid=dremio_space.guid,
        type_name=dremio_space.type_name,
        status=dremio_space.status,
        version=dremio_space.version,
        create_time=dremio_space.create_time,
        update_time=dremio_space.update_time,
        created_by=dremio_space.created_by,
        updated_by=dremio_space.updated_by,
        classifications=dremio_space.classifications,
        classification_names=dremio_space.classification_names,
        meanings=dremio_space.meanings,
        labels=dremio_space.labels,
        business_attributes=dremio_space.business_attributes,
        custom_attributes=dremio_space.custom_attributes,
        pending_tasks=dremio_space.pending_tasks,
        proxy=dremio_space.proxy,
        is_incomplete=dremio_space.is_incomplete,
        provenance_type=dremio_space.provenance_type,
        home_id=dremio_space.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _dremio_space_from_nested(nested: DremioSpaceNested) -> DremioSpace:
    """Convert nested format to flat DremioSpace."""
    attrs = nested.attributes if nested.attributes is not UNSET else DremioSpaceAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DREMIO_SPACE_REL_FIELDS,
        DremioSpaceRelationshipAttributes
    )
    return DremioSpace(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dremio_space_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _dremio_space_to_nested_bytes(dremio_space: DremioSpace, serde: Serde) -> bytes:
    """Convert flat DremioSpace to nested JSON bytes."""
    return serde.encode(_dremio_space_to_nested(dremio_space))


def _dremio_space_from_nested_bytes(data: bytes, serde: Serde) -> DremioSpace:
    """Convert nested JSON bytes to flat DremioSpace."""
    nested = serde.decode(data, DremioSpaceNested)
    return _dremio_space_from_nested(nested)

